function RetroTable({ columns, data, sortable = true }) {
  const { div, span } = tags;
  const [sortCol, setSortCol] = createSignal(null);
  const [sortDir, setSortDir] = createSignal('asc');

  const colWidths = columns.map(c => c.width || 15);
  const totalWidth = colWidths.reduce((a, b) => a + b, 0) + columns.length + 1;

  const drawBorder = (left, mid, right, horiz) => {
    return left + colWidths.map(w => horiz.repeat(w)).join(mid) + right;
  };

  const drawRow = (cells, pad = ' ') => {
    return '│' + cells.map((cell, i) => {
      const str = String(cell || '').slice(0, colWidths[i] - 2);
      return pad + str.padEnd(colWidths[i] - 2) + pad;
    }).join('│') + '│';
  };

  const handleSort = (col) => {
    if (sortCol() === col) setSortDir(sortDir() === 'asc' ? 'desc' : 'asc');
    else { setSortCol(col); setSortDir('asc'); }
  };

  const sortedData = () => {
    if (!sortCol()) return data;
    return [...data].sort((a, b) => {
      const aVal = a[sortCol()], bVal = b[sortCol()];
      const cmp = aVal < bVal ? -1 : aVal > bVal ? 1 : 0;
      return sortDir() === 'asc' ? cmp : -cmp;
    });
  };

  return div({ class: css('term-panel _p2 _overflow[auto]') },
    div({ class: css('_whitespace[pre]') },
      drawBorder('┌', '┬', '┐', '─'),
      '\n',
      drawRow(columns.map(c => c.label)),
      '\n',
      drawBorder('├', '┼', '┤', '─'),
      '\n',
      ...sortedData().flatMap(row => [
        drawRow(columns.map(c => row[c.key])),
        '\n'
      ]),
      drawBorder('└', '┴', '┘', '─')
    )
  );
}

function SimpleTable({ columns, data }) {
  const { div, span } = tags;
  const colWidths = columns.map(c => c.width || 15);

  const drawRow = (cells) => {
    return cells.map((cell, i) => String(cell || '').padEnd(colWidths[i])).join(' | ');
  };

  const separator = colWidths.map(w => '-'.repeat(w)).join('-+-');

  return div({ class: css('term-panel _p2') },
    div({ class: css('_whitespace[pre]') },
      drawRow(columns.map(c => c.label)),
      '\n',
      separator,
      '\n',
      ...data.map(row => drawRow(columns.map(c => row[c.key])) + '\n')
    )
  );
}

function CompactTable({ columns, data }) {
  const { div } = tags;
  const colWidths = columns.map(c => c.width || 12);

  const drawRow = (cells) => cells.map((cell, i) =>
    String(cell || '').padEnd(colWidths[i])
  ).join('  ');

  return div({ class: css('term-panel _p2 _whitespace[pre]') },
    drawRow(columns.map(c => c.label)),
    '\n',
    colWidths.map(w => '─'.repeat(w)).join('  '),
    '\n',
    ...data.map(row => drawRow(columns.map(c => row[c.key])) + '\n')
  );
}

